157	    @Override
158	    public Long saveIncidentReport(IncidentReportSaveBO saveBO) {
159	        if (saveBO == null || saveBO.getIncidentDate() == null) {
160	            throw new BusinessException(CommonError.PARAM_ERROR);
161	        }
162	        Integer locationType = saveBO.getLocationType();
163	        if (!BuildingLocationTypeEnum.isValid(locationType)) {
164	            throw new BusinessException(IncidentReportEnum.LOCATION_TYPE_INVALID);
165	        }
166	        List<String> floors = saveBO.getFloors();
167	        if (BuildingLocationTypeEnum.INSIDE_BUILDING.getCode().equals(locationType)) {
168	            if (!BuildingFloorCodeEnum.allValid(floors)) {
169	                throw new BusinessException(IncidentReportEnum.FLOORS_REQUIRED_WHEN_INSIDE);
170	            }
171	        }
172	
173	        HseIncidentReportEntity entity = new HseIncidentReportEntity();
174	        entity.setIncidentReportId(IdWorker.getId());
175	        entity.setIncidentCode(generateIncidentCode());
176	        entity.setIncidentDate(saveBO.getIncidentDate());
177	        entity.setLocationType(locationType);
178	        entity.setStatus(IncidentReportStatusEnum.OPEN.getCode());
179	        entity.setReportedBy(UserContextHolder.getUserId());
180	        save(entity);
181	
182	        if (BuildingLocationTypeEnum.INSIDE_BUILDING.getCode().equals(locationType)
183	                && CollectionUtils.isNotEmpty(floors)) {
184	            persistFloors(entity.getIncidentReportId(), floors);
185	        }
186	        return entity.getIncidentReportId();
187	    }
188	
189	    private String generateIncidentCode() {
190	        int year = LocalDate.now().getYear();
191	        long seq = sequenceService.nextVal(SequenceCodeConstant.INCIDENT + "-" + year);
192	        return "INC-" + year + "-" + String.format("%04d", seq);
193	    }
