195	    private void persistFloors(Long incidentReportId, List<String> floorCodes) {
196	        List<HseIncidentReportFloorEntity> rows = new ArrayList<>(floorCodes.size());
197	        for (String code : floorCodes) {
198	            HseIncidentReportFloorEntity row = new HseIncidentReportFloorEntity();
199	            row.setIncidentReportId(incidentReportId);
200	            row.setFloorCode(code);
201	            rows.add(row);
202	        }
203	        hseIncidentReportFloorService.saveBatch(rows);
204	    }
