206	    @Override
207	    public Long saveIncidentReportDetail(IncidentReportDetailSaveBO saveBO) {
208	
209	        LambdaQueryWrapper<HseIncidentReportEntity> hseIncidentReportEntityLambdaQueryWrapper =
210	                new LambdaQueryWrapper<>();
211	        hseIncidentReportEntityLambdaQueryWrapper.eq(HseIncidentReportEntity::getIncidentReportId,
212	                saveBO.getIncidentReportId());
213	        HseIncidentReportEntity hseIncidentReportEntity = getOne(hseIncidentReportEntityLambdaQueryWrapper);
214	        if (hseIncidentReportEntity == null) {
215	            throw new BusinessException(CommonError.PARAM_ERROR);
216	        }
217	        // Auto-created incidents inherit date/location from the linked emergency activation
218	        // and must remain immutable from the detail page — silently ignore those fields.
219	        boolean autoCreated = hseIncidentReportEntity.getRelatedEmergencyId() != null;
220	        hseIncidentReportEntity.setConvertedAccident(saveBO.getConvertedAccident());
221	        if (!autoCreated) {
222	            hseIncidentReportEntity.setIncidentDate(saveBO.getIncidentDate());
223	            hseIncidentReportEntity.setLocationSystem(saveBO.getLocationSystem());
224	            hseIncidentReportEntity.setLocationSystemAr(saveBO.getLocationSystemAr());
225	        }
226	        hseIncidentReportEntity.setIncidentDetails(saveBO.getIncidentDetails());
227	        hseIncidentReportEntity.setIncidentDetailsAr(saveBO.getIncidentDetailsAr());
228	        hseIncidentReportEntity.setOtherImpact(saveBO.getOtherImpact());
229	        hseIncidentReportEntity.setActionsTaken(saveBO.getActionsTaken());
230	        hseIncidentReportEntity.setOtherImpactAr(saveBO.getOtherImpactAr());
231	        hseIncidentReportEntity.setActionsTakenAr(saveBO.getActionsTakenAr());
232	
233	        // ---- Group toggles ----
234	        hseIncidentReportEntity.setExternalPartyInvolved(saveBO.getExternalPartyInvolved());
235	        hseIncidentReportEntity.setEmployeeImpacted(saveBO.getEmployeeImpacted());
236	        hseIncidentReportEntity.setPropertyImpacted(saveBO.getPropertyImpacted());
237	        hseIncidentReportEntity.setOtherImpacted(saveBO.getOtherImpacted());
238	
239	        // ---- Employees (JSON column) ----
240	        if (Integer.valueOf(1).equals(saveBO.getEmployeeImpacted())
241	                && CollectionUtils.isNotEmpty(saveBO.getIncidentReportDetailEmployeeSaveBOs())) {
242	            hseIncidentReportEntity.setEmployeeInvolved(JsonUtil.toJSONString(saveBO.getIncidentReportDetailEmployeeSaveBOs()));
243	        } else {
244	            hseIncidentReportEntity.setEmployeeInvolved(null);
245	        }
246	        updateById(hseIncidentReportEntity);
247	
248	        Long incidentReportId = hseIncidentReportEntity.getIncidentReportId();
249	
250	        // ---- Properties child table ----
251	        LambdaQueryWrapper<HsePropertyImpactedEntity> propertyDeleteWrapper = new LambdaQueryWrapper<>();
252	        propertyDeleteWrapper.eq(HsePropertyImpactedEntity::getIncidentReportId, incidentReportId);
253	        hsePropertyImpactedService.remove(propertyDeleteWrapper);
254	        if (Integer.valueOf(1).equals(saveBO.getPropertyImpacted())
255	                && CollectionUtils.isNotEmpty(saveBO.getIncidentReportDetailPropertySaveBOs())) {
256	            ArrayList<HsePropertyImpactedEntity> propertyRows = new ArrayList<>();
257	            for (IncidentReportDetailPropertySaveBO p : saveBO.getIncidentReportDetailPropertySaveBOs()) {
258	                HsePropertyImpactedEntity row = new HsePropertyImpactedEntity();
259	                row.setPropertyName(p.getPropertyName());
260	                row.setPropertyNameAr(p.getPropertyNameAr());
261	                row.setNatureOfDamage(p.getNatureOfDamage());
262	                row.setNatureOfDamageAr(p.getNatureOfDamageAr());
263	                row.setIncidentReportId(incidentReportId);
264	                row.setPropertyImpactedId(IdWorker.getId());
265	                propertyRows.add(row);
266	            }
267	            hsePropertyImpactedService.saveBatch(propertyRows);
268	        }
269	
270	        // ---- External Party child table ----
271	        persistExternalParties(incidentReportId, saveBO);
272	
273	        // ---- Issues child table ----
274	        persistIssues(incidentReportId, saveBO);
275	
276	        // ---- Basic-Info attachment ----
277	        List<AttachmentDTO> attachmentList = saveBO.getAttachmentList();
278	        if (CollectionUtils.isNotEmpty(attachmentList)) {
279	            processAttachment(incidentReportId, attachmentList, AttachTypeEnum.INCIDENT_REPORT);
280	        }
281	        return incidentReportId;
282	    }
