284	    /**
285	     * Replace external-party rows for the incident and sync per-row attachments.
286	     * If the group toggle is off, clear all rows + attachments.
287	     */
288	    private void persistExternalParties(Long incidentReportId, IncidentReportDetailSaveBO saveBO) {
289	        boolean groupOn = Integer.valueOf(1).equals(saveBO.getExternalPartyInvolved())
290	                && CollectionUtils.isNotEmpty(saveBO.getExternalParties());
291	
292	        // Cleanup attachments tied to old party rows (collect old ids first, since rows will be soft-deleted)
293	        List<HseIncidentExternalPartyEntity> existing = hseIncidentExternalPartyService.listByIncidentReportId(incidentReportId);
294	        for (HseIncidentExternalPartyEntity old : existing) {
295	            attachmentService.deleteAttachByBiz(old.getId(), AttachTypeEnum.INCIDENT_EXTERNAL_PARTY.getCode());
296	        }
297	
298	        if (!groupOn) {
299	            hseIncidentExternalPartyService.replaceForIncident(incidentReportId, Collections.emptyList());
300	            return;
301	        }
302	
303	        // Validate party type + dedupe per-type
304	        java.util.Set<Integer> seen = new java.util.HashSet<>();
305	        for (IncidentReportExternalPartySaveBO item : saveBO.getExternalParties()) {
306	            if (!ExternalPartyTypeEnum.isValid(item.getPartyType())) {
307	                throw new BusinessException(IncidentReportEnum.EXTERNAL_PARTY_TYPE_INVALID);
308	            }
309	            if (!seen.add(item.getPartyType())) {
310	                throw new BusinessException(IncidentReportEnum.EXTERNAL_PARTY_DUPLICATE);
311	            }
312	        }
313	
314	        // Insert new rows
315	        List<HseIncidentExternalPartyEntity> rows = new ArrayList<>();
316	        for (IncidentReportExternalPartySaveBO item : saveBO.getExternalParties()) {
317	            HseIncidentExternalPartyEntity row = new HseIncidentExternalPartyEntity();
318	            row.setIncidentReportId(incidentReportId);
319	            row.setPartyType(item.getPartyType());
320	            row.setResponseDetailsEn(item.getResponseDetailsEn());
321	            row.setResponseDetailsAr(item.getResponseDetailsAr());
322	            rows.add(row);
323	        }
324	        hseIncidentExternalPartyService.replaceForIncident(incidentReportId, rows);
325	
326	        // After saveBatch, MyBatis-Plus fills in row.id; bind attachments
327	        for (int i = 0; i < rows.size(); i++) {
328	            List<AttachmentDTO> atts = saveBO.getExternalParties().get(i).getAttachmentList();
329	            if (CollectionUtils.isNotEmpty(atts)) {
330	                attachmentService.syncBizAttachments(rows.get(i).getId(), AttachTypeEnum.INCIDENT_EXTERNAL_PARTY, atts);
331	            }
332	        }
333	    }
334	
335	    /**
336	     * Replace issue rows for the incident and sync per-row attachments.
337	     */
338	    private void persistIssues(Long incidentReportId, IncidentReportDetailSaveBO saveBO) {
339	        // Cleanup attachments tied to old issue rows
340	        List<HseIncidentIssueEntity> existing = hseIncidentIssueService.listByIncidentReportId(incidentReportId);
341	        for (HseIncidentIssueEntity old : existing) {
342	            attachmentService.deleteAttachByBiz(old.getId(), AttachTypeEnum.INCIDENT_ISSUE.getCode());
343	        }
344	
345	        if (CollectionUtils.isEmpty(saveBO.getIssues())) {
346	            hseIncidentIssueService.replaceForIncident(incidentReportId, Collections.emptyList());
347	            return;
348	        }
349	
350	        for (IncidentReportIssueSaveBO item : saveBO.getIssues()) {
351	            if (StringUtils.isBlank(item.getNotesRemarksEn()) && StringUtils.isBlank(item.getNotesRemarksAr())) {
352	                throw new BusinessException(IncidentReportEnum.ISSUE_NOTES_REQUIRED);
353	            }
354	            if (StringUtils.isBlank(item.getCorrectiveActionEn()) && StringUtils.isBlank(item.getCorrectiveActionAr())) {
355	                throw new BusinessException(IncidentReportEnum.ISSUE_CORRECTIVE_ACTION_REQUIRED);
356	            }
357	            if (item.getResponsibleOrgId() == null) {
358	                throw new BusinessException(IncidentReportEnum.ISSUE_RESPONSIBLE_ORG_REQUIRED);
359	            }
360	            if (item.getTargetClosureDate() == null) {
361	                throw new BusinessException(IncidentReportEnum.ISSUE_TARGET_CLOSURE_DATE_REQUIRED);
362	            }
363	        }
364	
365	        List<HseIncidentIssueEntity> rows = new ArrayList<>();
366	        for (IncidentReportIssueSaveBO item : saveBO.getIssues()) {
367	            HseIncidentIssueEntity row = new HseIncidentIssueEntity();
368	            row.setIncidentReportId(incidentReportId);
369	            row.setNotesRemarksEn(item.getNotesRemarksEn());
370	            row.setNotesRemarksAr(item.getNotesRemarksAr());
371	            row.setCorrectiveActionEn(item.getCorrectiveActionEn());
372	            row.setCorrectiveActionAr(item.getCorrectiveActionAr());
373	            row.setResponsibleOrgId(item.getResponsibleOrgId());
374	            row.setTargetClosureDate(item.getTargetClosureDate());
375	            rows.add(row);
376	        }
377	        hseIncidentIssueService.replaceForIncident(incidentReportId, rows);
378	
379	        for (int i = 0; i < rows.size(); i++) {
380	            List<AttachmentDTO> atts = saveBO.getIssues().get(i).getAttachmentList();
381	            if (CollectionUtils.isNotEmpty(atts)) {
382	                attachmentService.syncBizAttachments(rows.get(i).getId(), AttachTypeEnum.INCIDENT_ISSUE, atts);
383	            }
384	        }
385	    }
