387	    @Override
388	    public PageResult<IncidentReportPageBO> incidentReportPage(IncidentReportQueryBO query) {
389	        Page<HseIncidentReportEntity> page = new Page<>(query.getPageNum(), query.getPageSize());
390	        LambdaQueryWrapper<HseIncidentReportEntity> hseIncidentReportEntityLambdaQueryWrapper =
391	                new LambdaQueryWrapper<>();
392	        if (query.getStatus() != null) {
393	            hseIncidentReportEntityLambdaQueryWrapper.eq(HseIncidentReportEntity::getStatus, query.getStatus());
394	        }
395	
396	        // 双语字段必须 (En OR Ar) 括在一组 AND 内，否则 .or() 会与 status 等条件错误拼接
397	        if (StringUtils.isNotBlank(query.getIncidentDetails())) {
398	            String incidentKeyword = query.getIncidentDetails().trim();
399	            hseIncidentReportEntityLambdaQueryWrapper.and(w -> w
400	                    .like(HseIncidentReportEntity::getIncidentDetails, incidentKeyword)
401	                    .or()
402	                    .like(HseIncidentReportEntity::getIncidentDetailsAr, incidentKeyword));
403	        }
404	
405	        if (StringUtils.isNotBlank(query.getLocationSystem())) {
406	            String locationKeyword = query.getLocationSystem().trim();
407	            hseIncidentReportEntityLambdaQueryWrapper.and(w -> w
408	                    .like(HseIncidentReportEntity::getLocationSystem, locationKeyword)
409	                    .or()
410	                    .like(HseIncidentReportEntity::getLocationSystemAr, locationKeyword));
411	        }
412	
413	        if (query.getCovertToAccident() != null) {
414	            // 「否」：库中多为 0 或 NULL（旧数据未落库 0）；仅 eq(0) 会漏掉 NULL
415	            if (Integer.valueOf(0).equals(query.getCovertToAccident())) {
416	                hseIncidentReportEntityLambdaQueryWrapper.and(w -> w
417	                        .isNull(HseIncidentReportEntity::getConvertedAccident)
