443	        // Bulk load floors for all incidents on this page
444	        List<Long> incidentIds = hseIncidentReportPage.getRecords().stream()
445	                .map(HseIncidentReportEntity::getIncidentReportId)
446	                .collect(Collectors.toList());
447	        Map<Long, List<String>> floorsByIncident = hseIncidentReportFloorService
448	                .listByIncidentReportIds(incidentIds).stream()
449	                .collect(Collectors.groupingBy(
450	                        HseIncidentReportFloorEntity::getIncidentReportId,
451	                        Collectors.mapping(HseIncidentReportFloorEntity::getFloorCode, Collectors.toList())));
452	
453	        // Bulk load activation codes for auto-created incidents
454	        List<Long> activationIds = hseIncidentReportPage.getRecords().stream()
455	                .map(HseIncidentReportEntity::getRelatedEmergencyId)
456	                .filter(Objects::nonNull)
457	                .distinct()
458	                .collect(Collectors.toList());
459	        Map<Long, String> activationCodeById = new HashMap<>();
460	        if (!activationIds.isEmpty()) {
461	            LambdaQueryWrapper<HseEmResponseActivation> activationWrapper = new LambdaQueryWrapper<>();
462	            activationWrapper.in(HseEmResponseActivation::getActivationId, activationIds);
463	            List<HseEmResponseActivation> activations = hseEmResponseActivationMapper.selectList(activationWrapper);
464	            activationCodeById = activations.stream()
465	                    .collect(Collectors.toMap(HseEmResponseActivation::getActivationId,
466	                            a -> a.getActivationCode() == null ? "" : a.getActivationCode()));
467	        }
468	
469	        ArrayList<IncidentReportPageBO> incidentReportPageBOS = new ArrayList<>();
470	        for (HseIncidentReportEntity hseIncidentReportEntity : hseIncidentReportPage.getRecords()) {
471	            IncidentReportPageBO incidentReportPageBO = new IncidentReportPageBO();
472	            incidentReportPageBO.setIncidentReportId(hseIncidentReportEntity.getIncidentReportId());
473	            incidentReportPageBO.setIncidentCode(hseIncidentReportEntity.getIncidentCode());
474	            incidentReportPageBO.setIncidentDate(hseIncidentReportEntity.getIncidentDate());
475	            incidentReportPageBO.setLocationSystem(hseIncidentReportEntity.getLocationSystem());
476	            incidentReportPageBO.setLocationSystemAr(hseIncidentReportEntity.getLocationSystemAr());
477	            incidentReportPageBO.setIncidentDetails(hseIncidentReportEntity.getIncidentDetails());
478	            incidentReportPageBO.setIncidentDetailsAr(hseIncidentReportEntity.getIncidentDetailsAr());
479	            incidentReportPageBO.setConvertedAccident(hseIncidentReportEntity.getConvertedAccident());
480	            UserEntity userEntity = userMap.get(hseIncidentReportEntity.getReportedBy());
481	            if (userEntity != null) {
482	                incidentReportPageBO.setReportedByName(userEntity.getFullName());
483	                incidentReportPageBO.setReportedByNameAr(userEntity.getFullNameAr());
484	            }
485	
486	            incidentReportPageBO.setReporterTitle("");
487	            incidentReportPageBO.setReporterTitleAr("");
488	            incidentReportPageBO.setReportDate(hseIncidentReportEntity.getCreateTime());
489	            incidentReportPageBO.setStatus(hseIncidentReportEntity.getStatus());
490	
491	            // New incident-detail fields
492	            Long relatedEmergencyId = hseIncidentReportEntity.getRelatedEmergencyId();
493	            incidentReportPageBO.setRelatedEmergencyId(relatedEmergencyId);
494	            incidentReportPageBO.setRelatedEmergencyCode(
495	                    relatedEmergencyId == null ? null : activationCodeById.get(relatedEmergencyId));
496	            incidentReportPageBO.setLocationType(hseIncidentReportEntity.getLocationType());
497	            incidentReportPageBO.setFloors(floorsByIncident.getOrDefault(
