631	    @Override
632	    public Long submit(Long incidentReportId) {
633	        LambdaQueryWrapper<HseIncidentReportEntity> hseIncidentReportEntityLambdaQueryWrapper =
634	                new LambdaQueryWrapper<>();
635	        hseIncidentReportEntityLambdaQueryWrapper.eq(HseIncidentReportEntity::getIncidentReportId, incidentReportId);
636	        HseIncidentReportEntity hseIncidentReportEntity = getOne(hseIncidentReportEntityLambdaQueryWrapper);
637	        if (hseIncidentReportEntity == null) {
638	            throw new BusinessException(CommonError.PARAM_ERROR);
639	        }
640	
641	        FlowableService flowableService =
642	                FlowableService.getBusinessImpl(FlowableImplEnum.INCIDENT_REPORT_IMPL.getImpl());
643	        UserLoginContext loginUser = UserContextHolder.getUser();
644	
645	        // 判断是否已有流程实例（被拒绝后重新提交）
646	        if (hseIncidentReportEntity.getProcInstId() != null && !hseIncidentReportEntity.getProcInstId().isEmpty()) {
647	
648	            // 自动完成提交申请任务并设置提交人变量
649	            Task task = flowableService.getOneTask(hseIncidentReportEntity.getProcInstId());
650	            if (Objects.nonNull(task)) {
651	                Map<String, Object> variables = new HashMap<>();
652	                // 1. 设置不带后缀的变量（供监听器使用）
653	                variables.put(FlowableConstant.FLOWABLE_VARIABLE_SUBMITTER, String.valueOf(loginUser.getUserId()));
654	                // 2. 设置带taskId后缀的变量（用于历史查询，避免被覆盖）
655	                String taskIdSuffix = "_" + task.getId().replace("-", "_");
656	                variables.put(FlowableConstant.FLOWABLE_VARIABLE_SUBMITTER + taskIdSuffix,
657	                        String.valueOf(loginUser.getUserId()));
658	                flowableService.complete(task.getId(), variables);
659	            }
660	
661	        } else {
662	            // 首次提交，启动新流程
663	            FlowableStartProcessBO flowableStartProcessBO = new FlowableStartProcessBO();
664	            flowableStartProcessBO.setProcessId(FlowableConstant.FLOWABLE_PROCESS_INCIDENT_REPORT_KEY);
665	            flowableStartProcessBO.setBusinessId(hseIncidentReportEntity.getIncidentReportId());
666	            flowableStartProcessBO.setUserId(loginUser.getUserId());
667	            ProcessInstance processInstance = flowableService.startProcessInstance(flowableStartProcessBO);
668	
669	            // 自动完成提交申请任务并设置提交人变量
670	            Task task = flowableService.getOneTask(processInstance.getId());
671	            if (Objects.nonNull(task)) {
672	                Map<String, Object> variables = new HashMap<>();
673	                // 1. 设置不带后缀的变量（供BPMN流程和监听器使用）
674	                variables.put(FlowableConstant.FLOWABLE_VARIABLE_SUBMITTER, String.valueOf(loginUser.getUserId()));
675	                // 2. 设置带taskId后缀的变量（用于历史查询，避免被覆盖）
676	                String taskIdSuffix = "_" + task.getId().replace("-", "_");
677	                variables.put(FlowableConstant.FLOWABLE_VARIABLE_SUBMITTER + taskIdSuffix,
678	                        String.valueOf(loginUser.getUserId()));
679	                flowableService.complete(task.getId(), variables);
680	            }
681	
682	            hseIncidentReportEntity.setProcInstId(processInstance.getId());
683	        }
684	
685	        // 更新上报人、状态为待审核
686	        hseIncidentReportEntity.setStatus(IncidentReportStatusEnum.UNDER_REVIEW.getCode());
687	        updateById(hseIncidentReportEntity);
688	
689	        return incidentReportId;
690	    }
