692	    @Override
693	    public Long approval(IncidentReportApprovalBO approvalBO) {
694	        LambdaQueryWrapper<HseIncidentReportEntity> hseIncidentReportEntityLambdaQueryWrapper =
695	                new LambdaQueryWrapper<>();
696	        hseIncidentReportEntityLambdaQueryWrapper.eq(HseIncidentReportEntity::getIncidentReportId,
697	                approvalBO.getIncidentReportId());
698	        HseIncidentReportEntity hseIncidentReportEntity = getOne(hseIncidentReportEntityLambdaQueryWrapper);
699	        if (hseIncidentReportEntity == null) {
700	            throw new BusinessException(CommonError.PARAM_ERROR);
701	        }
702	
703	        UserLoginContext loginUser = UserContextHolder.getUser();
704	        List<String> candidateGroupList = new ArrayList<>();
705	        List<Long> userRoleIds =
706	                loginUser.getRoleList().stream().map(LoginRole::getRoleId).collect(Collectors.toList());
707	
708	        if (userRoleIds.contains(SysRoleEnum.HSE_MANAGER.getCode())) {
709	            // 第二步审批：无 org 限制
710	            candidateGroupList.add(SysRoleEnum.HSE_MANAGER.name());
711	        }
712	
713	        if (CollectionUtil.isEmpty(candidateGroupList)) {
714	            throw new BusinessException(AuthError.WITHOUT_DATA_PERMISSION);
715	        }
716	
717	        FlowableService flowableService =
718	                FlowableService.getBusinessImpl(FlowableImplEnum.INCIDENT_REPORT_IMPL.getImpl());
719	        List<Task> taskList =
720	                flowableService.getTaskListByCandidateGroups(hseIncidentReportEntity.getProcInstId(), candidateGroupList);
721	
722	        if (CollectionUtil.isEmpty(taskList)) {
723	            throw new BusinessException(AuthError.WITHOUT_DATA_PERMISSION);
724	        }
725	
726	        // 取第一个任务进行审批
727	        Task task = taskList.get(0);
728	
729	        FlowableCompleteProcessBO completeProcessBO = new FlowableCompleteProcessBO();
730	        completeProcessBO.setTask(task);
731	        completeProcessBO.setApprovalResult(FlowableConstant.FLOWABLE_RESULT_APPROVED);
732	        completeProcessBO.setComments(approvalBO.getComments());
733	        completeProcessBO.setUserId(loginUser.getUserId());
734	        flowableService.complete(completeProcessBO);
735	
736	        // 检查是否还有剩余任务
737	        List<Task> remainingTaskList = flowableService.getTaskList(hseIncidentReportEntity.getProcInstId());
738	
739	        if (CollectionUtil.isEmpty(remainingTaskList)) {
740	            hseIncidentReportEntity.setStatus(IncidentReportStatusEnum.APPROVED.getCode());
741	            updateById(hseIncidentReportEntity);
742	
743	            // Promote draft issues to corrective_action rows (idempotent).
744	            promoteIssuesToCorrectiveActions(hseIncidentReportEntity);
745	
746	            // Auto-close the linked emergency activation (if any) — last step of the flow.
747	            if (hseIncidentReportEntity.getRelatedEmergencyId() != null) {
748	                closeRelatedActivation(hseIncidentReportEntity.getRelatedEmergencyId(), loginUser);
749	            }
750	        }
751	        return approvalBO.getIncidentReportId();
752	    }
