754	    /**
755	     * On incident approval, copy each {@link HseIncidentIssueEntity} row into the
756	     * {@code hse_corrective_action} table and mark the issue with the generated id.
757	     * Idempotent: issues already carrying {@code promotedCorrectiveActionId} are skipped.
758	     */
759	    private void promoteIssuesToCorrectiveActions(HseIncidentReportEntity report) {
760	        List<HseIncidentIssueEntity> issues = hseIncidentIssueService.listByIncidentReportId(report.getIncidentReportId());
761	        if (CollectionUtils.isEmpty(issues)) {
762	            return;
763	        }
764	        int index = 0;
765	        for (HseIncidentIssueEntity issue : issues) {
766	            if (issue.getPromotedCorrectiveActionId() != null) {
767	                index++;
768	                continue;
769	            }
770	
771	            HseCorrectiveActionEntity ca = new HseCorrectiveActionEntity();
772	            ca.setCorrectiveActionId(IdWorker.getId());
773	            ca.setType(CorrectiveActionTypeEnum.INCIDENT.getCode());
774	            ca.setSourceId(report.getIncidentReportId());
775	            ca.setSourceAnswerId(issue.getId());
776	            ca.setOrgId(issue.getResponsibleOrgId());
777	            ca.setFindingRemark(issue.getNotesRemarksEn());
778	            ca.setFindingRemarkAr(issue.getNotesRemarksAr());
779	            ca.setCorrectiveAction(issue.getCorrectiveActionEn());
780	            ca.setCorrectiveActionAr(issue.getCorrectiveActionAr());
781	            ca.setTargetClosureDate(issue.getTargetClosureDate());
782	            ca.setStatus(CorrectiveActionStatusEnum.OPEN.getCode());
783	            ca.setPrimaryFinding(index == 0 ? 1 : 0);
784	            // 与 inspection/patrol 路径对齐：promoted CA 也分配 CA-YYYY-NNNN 业务编号
785	            ca.setCode(hseCodeSequenceService.nextCode(CodeTypeEnum.CORRECTIVE));
786	            hseCorrectiveActionService.save(ca);
787	
788	            // Copy issue attachments to the new corrective_action namespace so the CA detail page
789	            // shows the same files (without breaking issue detail display).
790	            List<AttachmentEntity> issueAttachments = attachmentService.list(Wrappers.lambdaQuery(AttachmentEntity.class)
791	                    .eq(AttachmentEntity::getBizId, issue.getId())
792	                    .eq(AttachmentEntity::getBizType, AttachTypeEnum.INCIDENT_ISSUE.getCode()));
793	            for (AttachmentEntity src : issueAttachments) {
794	                AttachmentEntity copy = new AttachmentEntity();
795	                BeanUtil.copyProperties(src, copy);
796	                copy.setId(null);
797	                copy.setBizId(ca.getCorrectiveActionId());
798	                copy.setBizType(AttachTypeEnum.CORRECTIVE_ACTION.getCode());
799	                attachmentService.save(copy);
800	            }
801	
802	            issue.setPromotedCorrectiveActionId(ca.getCorrectiveActionId());
803	            hseIncidentIssueService.updateById(issue);
804	            index++;
805	        }
806	    }
