808	    /**
809	     * Move the linked emergency activation to CLOSED and append a timeline activity row.
810	     * Idempotent: returns silently if the activation is already closed.
811	     */
812	    private void closeRelatedActivation(Long activationId, UserLoginContext approver) {
813	        HseEmResponseActivation activation = hseEmResponseActivationMapper.selectOne(
814	                new LambdaQueryWrapper<HseEmResponseActivation>()
815	                        .eq(HseEmResponseActivation::getActivationId, activationId)
816	                        .last("LIMIT 1"));
817	        if (activation == null) {
818	            return;
819	        }
820	        Integer closedCode = HseEmActivationStatusEnum.CLOSED.getCode();
821	        if (closedCode.equals(activation.getCurrentStep())) {
822	            return;
823	        }
824	
825	        LocalDateTime now = LocalDateTime.now();
826	        Long approverUserId = approver != null ? approver.getUserId() : null;
827	        activation.setCurrentStep(closedCode);
828	        activation.setClosedBy(approverUserId);
829	        activation.setClosedTime(now);
830	        if (activation.getResponseCompletionTime() == null) {
831	            activation.setResponseCompletionTime(now);
832	        }
833	        hseEmResponseActivationMapper.updateById(activation);
834	    }
