912	        } else {
913	            approveDetailBO.setApproveFlag(GlobalConstant.FLAG_NO);
914	        }
915	
916	        List<HistoricActivityInstance> historicActivityInstances =
917	                flowableService.getHistoricUserTaskActivityList(hseIncidentReportEntity.getProcInstId());
918	
919	        List<IncidentReportApproveListBO> incidentReportApproveListBOS = new ArrayList<>();
