940	                    }
941	                    String taskIdSuffix = "_" + taskId.replace("-", "_");
942	                    String submitterVarName = FlowableConstant.FLOWABLE_VARIABLE_SUBMITTER + taskIdSuffix;
943	
944	                    HistoricVariableInstance submitterVariable = historyService.createHistoricVariableInstanceQuery()
