948	
949	                    if (Objects.nonNull(submitterVariable)) {
950	                        approveListBO.setOperUserId(Long.valueOf(String.valueOf(submitterVariable.getValue())));
951	                    }
952	
953	                    if (Objects.nonNull(activity.getEndTime())) {
