958	
959	                } else if (FlowableTaskDefinitionEnum.INCIDENT_REPORT_ADMIN_APPROVAL.getTaskDefinition()
960	                        .equals(activity.getActivityId())) {
961	                    approveListBO.setApproveStatus(ApproveStatusEnum.PENDING_APPROVAL.getCode());
962	
963	                    // 使用taskId构造变量名后缀，精确查询该任务的审批变量
