970	                    }
971	                    String taskIdSuffix = "_" + taskId.replace("-", "_");
972	                    String approverVarName = FlowableConstant.FLOWABLE_VARIABLE_ADMIN_APPROVAL_USERID + taskIdSuffix;
973	                    String resultVarName = FlowableConstant.FLOWABLE_VARIABLE_APPROVAL_RESULT + taskIdSuffix;
974	                    String commentsVarName = FlowableConstant.FLOWABLE_VARIABLE_APPROVAL_COMMENTS + taskIdSuffix;
975	
976	                    // 查询该任务的审批人变量
977	                    HistoricVariableInstance approverVariable = historyService.createHistoricVariableInstanceQuery()
978	                            .processInstanceId(activity.getProcessInstanceId())
979	                            .variableName(approverVarName)
980	                            .singleResult();
981	
982	                    // 查询该任务的审批结果变量
983	                    HistoricVariableInstance resultVariable = historyService.createHistoricVariableInstanceQuery()
984	                            .processInstanceId(activity.getProcessInstanceId())
985	                            .variableName(resultVarName)
