1091	        }
1092	        HseIncidentReportEntity entity = getById(incidentReportId);
1093	        if (entity == null) {
1094	            throw new BusinessException(CommonError.PARAM_ERROR);
1095	        }
1096	        if (entity.getRelatedEmergencyId() != null) {
1097	            throw new BusinessException(IncidentReportEnum.AUTO_CREATED_CANNOT_BE_DELETED);
1098	        }
1099	        if (!IncidentReportStatusEnum.OPEN.getCode().equals(entity.getStatus())) {
1100	            throw new BusinessException(IncidentReportEnum.ONLY_OPEN_CAN_BE_DELETED);
1101	        }
1102	        // Soft-delete the parent + all child rows (floors, properties, external parties, issues, attachments)
1103	        removeById(incidentReportId);
1104	
1105	        LambdaQueryWrapper<HseIncidentReportFloorEntity> floorWrapper = new LambdaQueryWrapper<>();
1106	        floorWrapper.eq(HseIncidentReportFloorEntity::getIncidentReportId, incidentReportId);
1107	        hseIncidentReportFloorService.remove(floorWrapper);
1108	
1109	        LambdaQueryWrapper<HsePropertyImpactedEntity> propertyWrapper = new LambdaQueryWrapper<>();
1110	        propertyWrapper.eq(HsePropertyImpactedEntity::getIncidentReportId, incidentReportId);
1111	        hsePropertyImpactedService.remove(propertyWrapper);
1112	
1113	        // External party rows + their per-row attachments
1114	        List<HseIncidentExternalPartyEntity> parties = hseIncidentExternalPartyService.listByIncidentReportId(incidentReportId);
