1118	        hseIncidentExternalPartyService.replaceForIncident(incidentReportId, Collections.emptyList());
1119	
1120	        // Issue rows + their per-row attachments (issues can only be deleted while OPEN — never promoted yet)
1121	        List<HseIncidentIssueEntity> issues = hseIncidentIssueService.listByIncidentReportId(incidentReportId);
1122	        for (HseIncidentIssueEntity issue : issues) {
1123	            attachmentService.deleteAttachByBiz(issue.getId(), AttachTypeEnum.INCIDENT_ISSUE.getCode());
1124	        }
1125	        hseIncidentIssueService.replaceForIncident(incidentReportId, Collections.emptyList());
1126	
1127	        // Basic-Info attachments
1128	        attachmentService.deleteAttachByBiz(incidentReportId, AttachTypeEnum.INCIDENT_REPORT.getCode());
